import java.io.*;
import java.util.*;

public class Main {
    static class FastScanner {
        private StringTokenizer st;
        FastScanner() throws IOException {
            // Read entire input as a string
            byte[] data = System.in.readAllBytes();
            String s = new String(data);
            // Replace escaped newline sequences with spaces to act as delimiters
            s = s.replace("\\n", " ");
            // Also replace escaped carriage returns if any
            s = s.replace("\\r", " ");
            st = new StringTokenizer(s);
        }
        String next() {
            return st.hasMoreTokens() ? st.nextToken() : null;
        }
        int nextInt() {
            return Integer.parseInt(next());
        }
    }

    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner();
        String tStr = fs.next();
        if (tStr == null) return;
        int T = Integer.parseInt(tStr);
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            int n = fs.nextInt();
            int m = fs.nextInt();
            @SuppressWarnings("unchecked")
            ArrayList<Integer>[] adj = new ArrayList[n + 1];
            for (int i = 1; i <= n; i++) adj[i] = new ArrayList<>();
            for (int i = 0; i < m; i++) {
                int a = fs.nextInt();
                int b = fs.nextInt();
                if (a >= 1 && a <= n) adj[a].add(b);
            }
            boolean[] vis = new boolean[n + 1];
            ArrayDeque<Integer> dq = new ArrayDeque<>();
            dq.add(1);
            vis[1] = true;
            while (!dq.isEmpty()) {
                int v = dq.poll();
                for (int u : adj[v]) {
                    if (!vis[u]) {
                        vis[u] = true;
                        dq.add(u);
                    }
                }
            }
            boolean first = true;
            for (int i = 1; i <= n; i++) {
                if (vis[i]) {
                    if (!first) out.append(' ');
                    out.append(i);
                    first = false;
                }
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
}

